  1	import type { ComponentPublicInstance, Ref } from 'vue';
  2	import { onMounted, onUnmounted, ref } from 'vue';
  3	
  4	type ShortcutHandler = (event: KeyboardEvent, cancelNext: () => void) => void | any | boolean;
  5	
  6	export const keyMap: Record<string, string> = {
  7		Control: 'meta',
  8		Command: 'meta',
  9	};
 10	
 11	export const systemKeys = ['meta', 'shift', 'alt', 'backspace', 'delete', 'tab', 'capslock', 'enter', 'home', 'end'];
 12	
 13	const keysDown: Set<string> = new Set([]);
 14	const handlers: Record<string, ShortcutHandler[]> = {};
 15	
 16	document.body.addEventListener('keydown', (event: KeyboardEvent) => {
 17		if (event.repeat || !event.key) return;
 18	
 19		keysDown.add(mapKeys(event));
 20		callHandlers(event);
 21	});
 22	
 23	document.body.addEventListener('keyup', (event: KeyboardEvent) => {
 24		if (event.repeat || !event.key) return;
 25		keysDown.clear();
 26	});
 27	
 28	export function useShortcut(
 29		shortcuts: string | string[],
 30		handler: ShortcutHandler,
 31		reference: Ref<HTMLElement | undefined> | Ref<ComponentPublicInstance | undefined> = ref(
 32			document.body,
 33		) as Ref<HTMLElement>,
 34	): void {
 35		const callback: ShortcutHandler = (event, cancelNext) => {
 36			if (!reference.value) return;
 37			const ref = reference.value instanceof HTMLElement ? reference.value : (reference.value.$el as HTMLElement);
 38	
 39			if (
 40				document.activeElement === ref ||
 41				ref.contains(document.activeElement) ||
 42				document.activeElement === document.body
 43			) {
 44				event.preventDefault();
 45				return handler(event, cancelNext);
 46			}
 47	
 48			return false;
 49		};
 50	
 51		onMounted(() => {
 52			[shortcuts].flat().forEach((shortcut) => {
 53				if (shortcut in handlers) {
 54					handlers[shortcut]?.unshift(callback);
 55				} else {
 56					handlers[shortcut] = [callback];
 57				}
 58			});
 59		});
 60	
 61		onUnmounted(() => {
 62			[shortcuts].flat().forEach((shortcut) => {
 63				const shortcutHandler = handlers[shortcut];
 64	
 65				if (shortcutHandler) {
 66					const filteredHandlers = shortcutHandler.filter((f) => f !== callback);
 67	
 68					handlers[shortcut] = filteredHandlers;
 69	
 70					if (filteredHandlers.length === 0) {
 71						delete handlers[shortcut];
 72					}
 73				}
 74			});
 75		});
 76	}
 77	
 78	function mapKeys(key: KeyboardEvent) {
 79		const isLatinAlphabet = /^[a-zA-Z0-9]*?$/g;
 80	
 81		let keyString = key.key.match(isLatinAlphabet) === null ? key.code.replace(/(Key|Digit)/g, '') : key.key;
 82	
 83		const keyStringInMap = keyMap[keyString];
 84	
 85		keyString = keyStringInMap ?? keyString;
 86		keyString = keyString.toLowerCase();
 87	
 88		return keyString;
 89	}
 90	
 91	function callHandlers(event: KeyboardEvent) {
 92		Object.entries(handlers).forEach(([key, value]) => {
 93			const keys = key.split('+');
 94	
 95			for (key of keysDown) {
 96				if (keys.includes(key) === false) return;
 97			}
 98	
 99			for (key of keys) {
100				if (keysDown.has(key) === false) return;
101			}
102	
103			for (let i = 0; i < value.length; i++) {
104				let cancel = false;
105	
106				value[i]?.(event, () => {
107					cancel = true;
108				});
109	
110				// if cancelNext is called, discontinue going through the queue.
111				if (typeof cancel === 'boolean' && cancel) break;
112			}
113		});
114	}

