  1	import { useEnv } from '@directus/env';
  2	import { ForbiddenError, InvalidPayloadError } from '@directus/errors';
  3	import type { SchemaInspector } from '@directus/schema';
  4	import { createInspector } from '@directus/schema';
  5	import { type BaseCollectionMeta, systemCollectionRows } from '@directus/system-data';
  6	import type {
  7		AbstractServiceOptions,
  8		Accountability,
  9		ActionEventParams,
 10		FieldMeta,
 11		FieldMutationOptions,
 12		MutationOptions,
 13		RawCollection,
 14		RawField,
 15		SchemaOverview,
 16	} from '@directus/types';
 17	import { addFieldFlag } from '@directus/utils';
 18	import type Keyv from 'keyv';
 19	import type { Knex } from 'knex';
 20	import { chunk, groupBy, merge, omit } from 'lodash-es';
 21	import { clearSystemCache, getCache } from '../cache.js';
 22	import { ALIAS_TYPES } from '../constants.js';
 23	import type { Helpers } from '../database/helpers/index.js';
 24	import { getHelpers } from '../database/helpers/index.js';
 25	import getDatabase, { getSchemaInspector } from '../database/index.js';
 26	import emitter from '../emitter.js';
 27	import { fetchAllowedCollections } from '../permissions/modules/fetch-allowed-collections/fetch-allowed-collections.js';
 28	import { validateAccess } from '../permissions/modules/validate-access/validate-access.js';
 29	import type { Collection } from '../types/index.js';
 30	import { getSchema } from '../utils/get-schema.js';
 31	import { shouldClearCache } from '../utils/should-clear-cache.js';
 32	import { transaction } from '../utils/transaction.js';
 33	import { buildCollectionAndFieldRelations } from './fields/build-collection-and-field-relations.js';
 34	import { getCollectionMetaUpdates } from './fields/get-collection-meta-updates.js';
 35	import { getCollectionRelationList } from './fields/get-collection-relation-list.js';
 36	import { FieldsService } from './fields.js';
 37	import { ItemsService } from './items.js';
 38	
 39	export class CollectionsService {
 40		knex: Knex;
 41		helpers: Helpers;
 42		accountability: Accountability | null;
 43		schemaInspector: SchemaInspector;
 44		schema: SchemaOverview;
 45		cache: Keyv<any> | null;
 46		systemCache: Keyv<any>;
 47	
 48		constructor(options: AbstractServiceOptions) {
 49			this.knex = options.knex || getDatabase();
 50			this.helpers = getHelpers(this.knex);
 51			this.accountability = options.accountability || null;
 52			this.schemaInspector = options.knex ? createInspector(options.knex) : getSchemaInspector();
 53			this.schema = options.schema;
 54	
 55			const { cache, systemCache } = getCache();
 56			this.cache = cache;
 57			this.systemCache = systemCache;
 58		}
 59	
 60		/**
 61		 * Create a single new collection
 62		 */
 63		async createOne(payload: RawCollection, opts?: FieldMutationOptions): Promise<string> {
 64			if (this.accountability && this.accountability.admin !== true) {
 65				throw new ForbiddenError();
 66			}
 67	
 68			if (!('collection' in payload)) throw new InvalidPayloadError({ reason: `"collection" is required` });
 69	
 70			if (typeof payload.collection !== 'string' || payload.collection === '') {
 71				throw new InvalidPayloadError({ reason: `"collection" must be a non-empty string` });
 72			}
 73	
 74			if (payload.collection.startsWith('directus_')) {
 75				throw new InvalidPayloadError({ reason: `Collections can't start with "directus_"` });
 76			}
 77	
 78			payload.collection = await this.helpers.schema.parseCollectionName(payload.collection);
 79	
 80			const nestedActionEvents: ActionEventParams[] = [];
 81	
 82			try {
 83				const existingCollections: string[] = [
 84					...((await this.knex.select('collection').from('directus_collections'))?.map(({ collection }) => collection) ??
 85						[]),
 86					...Object.keys(this.schema.collections),
 87				];
 88	
 89				if (existingCollections.includes(payload.collection)) {
 90					throw new InvalidPayloadError({ reason: `Collection "${payload.collection}" already exists` });
 91				}
 92	
 93				const attemptConcurrentIndex = Boolean(opts?.attemptConcurrentIndex);
 94	
 95				// Create the collection/fields in a transaction so it'll be reverted in case of errors or
 96				// permission problems. This might not work reliably in MySQL, as it doesn't support DDL in
 97				// transactions.
 98				await transaction(this.knex, async (trx) => {
 99					if (payload.schema) {
100						if ('fields' in payload && !Array.isArray(payload.fields)) {
101							throw new InvalidPayloadError({ reason: `"fields" must be an array` });
102						}
103	
104						/**
105						 * Directus heavily relies on the primary key of a collection, so we have to make sure that
106						 * every collection that is created has a primary key. If no primary key field is created
107						 * while making the collection, we default to an auto incremented id named `id`
108						 */
109	
110						const injectedPrimaryKeyField: RawField = {
111							field: 'id',
112							type: 'integer',
113							meta: {
114								hidden: true,
115								interface: 'numeric',
116								readonly: true,
117							},
118							schema: {
119								is_primary_key: true,
120								has_auto_increment: true,
121							},
122						};
123	
124						if (!payload.fields || payload.fields.length === 0) {
125							payload.fields = [injectedPrimaryKeyField];
126						} else if (
127							!payload.fields.some((f) => f.schema?.is_primary_key === true || f.schema?.has_auto_increment === true)
128						) {
129							payload.fields = [injectedPrimaryKeyField, ...payload.fields];
130						}
131	
132						// Ensure that every field meta has the field/collection fields filled correctly
133						payload.fields = payload.fields.map((field) => {
134							if (field.meta) {
135								field.meta = {
136									...field.meta,
137									field: field.field,
138									collection: payload.collection!,
139								};
140							}
141	
142							// Add flag for specific database type overrides
143							const flagToAdd = this.helpers.date.fieldFlagForField(field.type);
144	
145							if (flagToAdd) {
146								addFieldFlag(field, flagToAdd);
147							}
148	
149							return field;
150						});
151	
152						const fieldsService = new FieldsService({ knex: trx, schema: this.schema });
153	
154						await trx.schema.createTable(payload.collection, (table) => {
155							for (const field of payload.fields!) {
156								if (field.type && ALIAS_TYPES.includes(field.type) === false) {
157									fieldsService.addColumnToTable(table, payload.collection, field, {
158										attemptConcurrentIndex,
159									});
160								}
161							}
162						});
163	
164						const fieldItemsService = new ItemsService('directus_fields', {
165							knex: trx,
166							accountability: this.accountability,
167							schema: this.schema,
168						});
169	
170						const fieldPayloads = payload.fields!.filter((field) => field.meta).map((field) => field.meta) as FieldMeta[];
171	
172						// Sort new fields that does not have any group defined, in ascending order.
173						// Lodash merge is used so that the "sort" can be overridden if defined.
174						let sortedFieldPayloads = fieldPayloads
175							.filter((field) => field?.group === undefined || field?.group === null)
176							.map((field, index) => merge({ sort: index + 1 }, field));
177	
178						// Sort remaining new fields with group defined, if any, in ascending order.
179						// sortedFieldPayloads will be less than fieldPayloads if it filtered out any fields with group defined.
180						if (sortedFieldPayloads.length < fieldPayloads.length) {
181							const fieldsWithGroups = groupBy(
182								fieldPayloads.filter((field) => field?.group),
183								(field) => field?.group,
184							);
185	
186							// The sort order is restarted from 1 for fields in each group and appended to sortedFieldPayloads.
187							// Lodash merge is used so that the "sort" can be overridden if defined.
188							for (const [_group, fields] of Object.entries(fieldsWithGroups)) {
189								sortedFieldPayloads = sortedFieldPayloads.concat(
190									fields.map((field, index) => merge({ sort: index + 1 }, field)),
191								);
192							}
193						}
194	
195						await fieldItemsService.createMany(sortedFieldPayloads, {
196							bypassEmitAction: (params) =>
197								opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
198							bypassLimits: true,
199						});
200					}
201	
202					if (payload.meta) {
203						const collectionsItemsService = new ItemsService('directus_collections', {
204							knex: trx,
205							accountability: this.accountability,
206							schema: this.schema,
207						});
208	
209						await collectionsItemsService.createOne(
210							{
211								...payload.meta,
212								collection: payload.collection,
213							},
214							{
215								bypassEmitAction: (params) =>
216									opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
217							},
218						);
219					}
220	
221					return payload.collection;
222				});
223	
224				// concurrent index creation cannot be done inside the transaction
225				if (attemptConcurrentIndex && payload.schema && Array.isArray(payload.fields)) {
226					const fieldsService = new FieldsService({ schema: this.schema });
227	
228					for (const field of payload.fields) {
229						if (field.type && ALIAS_TYPES.includes(field.type) === false) {
230							await fieldsService.addColumnIndex(payload.collection, field, {
231								attemptConcurrentIndex,
232							});
233						}
234					}
235				}
236	
237				return payload.collection;
238			} finally {
239				if (shouldClearCache(this.cache, opts)) {
240					await this.cache.clear();
241				}
242	
243				if (opts?.autoPurgeSystemCache !== false) {
244					await clearSystemCache({ autoPurgeCache: opts?.autoPurgeCache });
245				}
246	
247				if (opts?.emitEvents !== false && nestedActionEvents.length > 0) {
248					const updatedSchema = await getSchema();
249	
250					for (const nestedActionEvent of nestedActionEvents) {
251						nestedActionEvent.context.schema = updatedSchema;
252						emitter.emitAction(nestedActionEvent.event, nestedActionEvent.meta, nestedActionEvent.context);
253					}
254				}
255			}
256		}
257	
258		/**
259		 * Create multiple new collections
260		 */
261		async createMany(payloads: RawCollection[], opts?: FieldMutationOptions): Promise<string[]> {
262			const nestedActionEvents: ActionEventParams[] = [];
263	
264			try {
265				const collections = await transaction(this.knex, async (trx) => {
266					const service = new CollectionsService({
267						schema: this.schema,
268						accountability: this.accountability,
269						knex: trx,
270					});
271	
272					const collectionNames: string[] = [];
273	
274					for (const payload of payloads) {
275						const name = await service.createOne(payload, {
276							autoPurgeCache: false,
277							autoPurgeSystemCache: false,
278							bypassEmitAction: (params) => nestedActionEvents.push(params),
279							attemptConcurrentIndex: Boolean(opts?.attemptConcurrentIndex),
280						});
281	
282						collectionNames.push(name);
283					}
284	
285					return collectionNames;
286				});
287	
288				return collections;
289			} finally {
290				if (shouldClearCache(this.cache, opts)) {
291					await this.cache.clear();
292				}
293	
294				if (opts?.autoPurgeSystemCache !== false) {
295					await clearSystemCache({ autoPurgeCache: opts?.autoPurgeCache });
296				}
297	
298				if (opts?.emitEvents !== false && nestedActionEvents.length > 0) {
299					const updatedSchema = await getSchema();
300	
301					for (const nestedActionEvent of nestedActionEvents) {
302						nestedActionEvent.context.schema = updatedSchema;
303						emitter.emitAction(nestedActionEvent.event, nestedActionEvent.meta, nestedActionEvent.context);
304					}
305				}
306			}
307		}
308	
309		/**
310		 * Read all collections. Currently doesn't support any query.
311		 */
312		async readByQuery(): Promise<Collection[]> {
313			const env = useEnv();
314	
315			const collectionsItemsService = new ItemsService('directus_collections', {
316				knex: this.knex,
317				schema: this.schema,
318				accountability: this.accountability,
319			});
320	
321			let tablesInDatabase = await this.schemaInspector.tableInfo();
322	
323			let meta = (await collectionsItemsService.readByQuery({
324				limit: -1,
325			})) as BaseCollectionMeta[];
326	
327			meta.push(...systemCollectionRows);
328	
329			if (this.accountability && this.accountability.admin !== true) {
330				const collectionsGroups: { [key: string]: string } = meta.reduce(
331					(meta, item) => ({
332						...meta,
333						[item.collection]: item.group,
334					}),
335					{},
336				);
337	
338				let collectionsYouHavePermissionToRead = await fetchAllowedCollections(
339					{
340						accountability: this.accountability,
341						action: 'read',
342					},
343					{
344						knex: this.knex,
345						schema: this.schema,
346					},
347				);
348	
349				for (const collection of collectionsYouHavePermissionToRead) {
350					const group = collectionsGroups[collection];
351					if (group) collectionsYouHavePermissionToRead.push(group);
352					delete collectionsGroups[collection];
353				}
354	
355				collectionsYouHavePermissionToRead = [...new Set([...collectionsYouHavePermissionToRead])];
356	
357				tablesInDatabase = tablesInDatabase.filter((table) => {
358					return collectionsYouHavePermissionToRead.includes(table.name);
359				});
360	
361				meta = meta.filter((collectionMeta) => {
362					return collectionsYouHavePermissionToRead.includes(collectionMeta.collection);
363				});
364			}
365	
366			const collections: Collection[] = [];
367	
368			for (const collectionMeta of meta) {
369				const collection: Collection = {
370					collection: collectionMeta.collection,
371					meta: collectionMeta,
372					schema: tablesInDatabase.find((table) => table.name === collectionMeta.collection) ?? null,
373				};
374	
375				collections.push(collection);
376			}
377	
378			for (const table of tablesInDatabase) {
379				const exists = !!collections.find(({ collection }) => collection === table.name);
380	
381				if (!exists) {
382					collections.push({
383						collection: table.name,
384						schema: table,
385						meta: null,
386					});
387				}
388			}
389	
390			if (env['DB_EXCLUDE_TABLES']) {
391				return collections.filter(
392					(collection) => (env['DB_EXCLUDE_TABLES'] as string[]).includes(collection.collection) === false,
393				);
394			}
395	
396			return collections;
397		}
398	
399		/**
400		 * Get a single collection by name
401		 */
402		async readOne(collectionKey: string): Promise<Collection> {
403			const result = await this.readMany([collectionKey]);
404	
405			if (result.length === 0) throw new ForbiddenError();
406	
407			return result[0]!;
408		}
409	
410		/**
411		 * Read many collections by name
412		 */
413		async readMany(collectionKeys: string[]): Promise<Collection[]> {
414			if (this.accountability) {
415				await Promise.all(
416					collectionKeys.map((collection) =>
417						validateAccess(
418							{
419								accountability: this.accountability!,
420								action: 'read',
421								collection,
422								skipCollectionExistsCheck: true,
423							},
424							{
425								schema: this.schema,
426								knex: this.knex,
427							},
428						),
429					),
430				);
431			}
432	
433			const collections = await this.readByQuery();
434			return collections.filter(({ collection }) => collectionKeys.includes(collection));
435		}
436	
437		/**
438		 * Update a single collection by name
439		 */
440		async updateOne(collectionKey: string, data: Partial<Collection>, opts?: MutationOptions): Promise<string> {
441			if (this.accountability && this.accountability.admin !== true) {
442				throw new ForbiddenError();
443			}
444	
445			const nestedActionEvents: ActionEventParams[] = [];
446	
447			try {
448				const collectionsItemsService = new ItemsService('directus_collections', {
449					knex: this.knex,
450					accountability: this.accountability,
451					schema: this.schema,
452				});
453	
454				const payload = data as Partial<Collection>;
455	
456				if (!payload.meta) {
457					return collectionKey;
458				}
459	
460				const exists = !!(await this.knex
461					.select('collection')
462					.from('directus_collections')
463					.where({ collection: collectionKey })
464					.first());
465	
466				if (exists) {
467					await collectionsItemsService.updateOne(collectionKey, payload.meta, {
468						...opts,
469						bypassEmitAction: (params) =>
470							opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
471					});
472				} else {
473					await collectionsItemsService.createOne(
474						{ ...payload.meta, collection: collectionKey },
475						{
476							...opts,
477							bypassEmitAction: (params) =>
478								opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
479						},
480					);
481				}
482	
483				return collectionKey;
484			} finally {
485				if (shouldClearCache(this.cache, opts)) {
486					await this.cache.clear();
487				}
488	
489				if (opts?.autoPurgeSystemCache !== false) {
490					await clearSystemCache({ autoPurgeCache: opts?.autoPurgeCache });
491				}
492	
493				if (opts?.emitEvents !== false && nestedActionEvents.length > 0) {
494					const updatedSchema = await getSchema();
495	
496					for (const nestedActionEvent of nestedActionEvents) {
497						nestedActionEvent.context.schema = updatedSchema;
498						emitter.emitAction(nestedActionEvent.event, nestedActionEvent.meta, nestedActionEvent.context);
499					}
500				}
501			}
502		}
503	
504		/**
505		 * Update multiple collections in a single transaction
506		 */
507		async updateBatch(data: Partial<Collection>[], opts?: MutationOptions): Promise<string[]> {
508			if (this.accountability && this.accountability.admin !== true) {
509				throw new ForbiddenError();
510			}
511	
512			if (!Array.isArray(data)) {
513				throw new InvalidPayloadError({ reason: 'Input should be an array of collection changes' });
514			}
515	
516			const collectionKey = 'collection';
517			const collectionKeys: string[] = [];
518			const nestedActionEvents: ActionEventParams[] = [];
519	
520			try {
521				await transaction(this.knex, async (trx) => {
522					const collectionItemsService = new CollectionsService({
523						knex: trx,
524						accountability: this.accountability,
525						schema: this.schema,
526					});
527	
528					for (const payload of data) {
529						if (!payload[collectionKey]) {
530							throw new InvalidPayloadError({ reason: `Collection in update misses collection key` });
531						}
532	
533						await collectionItemsService.updateOne(payload[collectionKey], omit(payload, collectionKey), {
534							autoPurgeCache: false,
535							autoPurgeSystemCache: false,
536							bypassEmitAction: (params) =>
537								opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
538						});
539	
540						collectionKeys.push(payload[collectionKey]);
541					}
542				});
543			} finally {
544				if (shouldClearCache(this.cache, opts)) {
545					await this.cache.clear();
546				}
547	
548				if (opts?.autoPurgeSystemCache !== false) {
549					await clearSystemCache({ autoPurgeCache: opts?.autoPurgeCache });
550				}
551	
552				if (opts?.emitEvents !== false && nestedActionEvents.length > 0) {
553					const updatedSchema = await getSchema();
554	
555					for (const nestedActionEvent of nestedActionEvents) {
556						nestedActionEvent.context.schema = updatedSchema;
