613		/**
614		 * Delete a single collection This will delete the table and all records within. It'll also
615		 * delete any fields, presets, activity, revisions, and permissions relating to this collection
616		 */
617		async deleteOne(collectionKey: string, opts?: MutationOptions): Promise<string> {
618			if (this.accountability && this.accountability.admin !== true) {
619				throw new ForbiddenError();
620			}
621	
622			const nestedActionEvents: ActionEventParams[] = [];
623	
624			try {
625				const collections = await this.readByQuery();
626	
627				const collectionToBeDeleted = collections.find((collection) => collection.collection === collectionKey);
628	
629				if (!!collectionToBeDeleted === false) {
630					throw new ForbiddenError();
631				}
632	
633				await transaction(this.knex, async (trx) => {
634					if (collectionToBeDeleted!.schema) {
635						await trx.schema.dropTable(collectionKey);
636					}
637	
638					// Make sure this collection isn't used as a group in any other collections
639					await trx('directus_collections').update({ group: null }).where({ group: collectionKey });
640	
641					if (collectionToBeDeleted!.meta) {
642						const collectionsItemsService = new ItemsService('directus_collections', {
643							knex: trx,
644							accountability: this.accountability,
645							schema: this.schema,
646						});
647	
648						await collectionsItemsService.deleteOne(collectionKey, {
649							bypassEmitAction: (params) =>
650								opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
651						});
652					}
653	
654					if (collectionToBeDeleted!.schema) {
655						const fieldsService = new FieldsService({
656							knex: trx,
657							accountability: this.accountability,
658							schema: this.schema,
659						});
660	
661						const fieldItemsService = new ItemsService('directus_fields', {
662							knex: trx,
663							accountability: this.accountability,
664							schema: this.schema,
665						});
666	
667						await fieldItemsService.deleteByQuery(
668							{
669								filter: {
670									collection: { _eq: collectionKey },
671								},
672							},
673							{
674								bypassEmitAction: (params) =>
675									opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
676							},
677						);
678	
679						await trx('directus_presets').delete().where('collection', '=', collectionKey);
680	
681						const revisionsToDelete = await trx
682							.select('id')
683							.from('directus_revisions')
684							.where({ collection: collectionKey });
685	
686						if (revisionsToDelete.length > 0) {
687							const chunks = chunk(
688								revisionsToDelete.map((record) => record.id),
689								10000,
690							);
691	
692							for (const keys of chunks) {
693								await trx('directus_revisions').update({ parent: null }).whereIn('parent', keys);
694							}
695						}
696	
697						await trx('directus_revisions').delete().where('collection', '=', collectionKey);
698	
699						await trx('directus_activity').delete().where('collection', '=', collectionKey);
700						await trx('directus_permissions').delete().where('collection', '=', collectionKey);
701						await trx('directus_relations').delete().where({ many_collection: collectionKey });
702	
703						const { collectionRelationTree, fieldToCollectionList } = await buildCollectionAndFieldRelations(
704							this.schema.relations,
705						);
706	
707						const collectionRelationList = getCollectionRelationList(collectionKey, collectionRelationTree);
708	
709						// only process duplication fields if related collections have them
710						if (collectionRelationList.size !== 0) {
711							const collectionMetas = await trx
712								.select('collection', 'archive_field', 'sort_field', 'item_duplication_fields')
713								.from('directus_collections')
714								.whereIn('collection', Array.from(collectionRelationList))
715								.whereNotNull('item_duplication_fields');
716	
717							await Promise.all(
718								Object.keys(this.schema.collections[collectionKey]?.fields ?? {}).map(async (fieldKey) => {
719									const collectionMetaUpdates = getCollectionMetaUpdates(
720										collectionKey,
721										fieldKey,
722										collectionMetas,
723										this.schema.collections,
724										fieldToCollectionList,
725									);
726	
727									for (const meta of collectionMetaUpdates) {
728										await trx('directus_collections').update(meta.updates).where({ collection: meta.collection });
729									}
730								}),
731							);
732						}
733	
734						const relations = this.schema.relations.filter((relation) => {
735							return relation.collection === collectionKey || relation.related_collection === collectionKey;
736						});
737	
738						for (const relation of relations) {
739							// Delete related o2m fields that point to current collection
740							if (relation.related_collection && relation.meta?.one_field) {
741								await fieldsService.deleteField(relation.related_collection, relation.meta.one_field, {
742									autoPurgeCache: false,
743									autoPurgeSystemCache: false,
744									bypassEmitAction: (params) =>
745										opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
746								});
747							}
748	
749							// Delete related m2o fields that point to current collection
750							if (relation.related_collection === collectionKey) {
751								await fieldsService.deleteField(relation.collection, relation.field, {
752									autoPurgeCache: false,
753									autoPurgeSystemCache: false,
754									bypassEmitAction: (params) =>
755										opts?.bypassEmitAction ? opts.bypassEmitAction(params) : nestedActionEvents.push(params),
756								});
757							}
758						}
759	
760						const a2oRelationsThatIncludeThisCollection = this.schema.relations.filter((relation) => {
761							return relation.meta?.one_allowed_collections?.includes(collectionKey);
762						});
763	
764						for (const relation of a2oRelationsThatIncludeThisCollection) {
765							const newAllowedCollections = relation
766								.meta!.one_allowed_collections!.filter((collection) => collectionKey !== collection)
767								.join(',');
768	
769							await trx('directus_relations')
770								.update({ one_allowed_collections: newAllowedCollections })
771								.where({ id: relation.meta!.id });
772						}
773					}
774				});
775	
776				return collectionKey;
777			} finally {
778				if (shouldClearCache(this.cache, opts)) {
779					await this.cache.clear();
780				}
781	
782				if (opts?.autoPurgeSystemCache !== false) {
783					await clearSystemCache({ autoPurgeCache: opts?.autoPurgeCache });
784				}
785	
786				if (opts?.emitEvents !== false && nestedActionEvents.length > 0) {
787					const updatedSchema = await getSchema();
788	
789					for (const nestedActionEvent of nestedActionEvents) {
790						nestedActionEvent.context.schema = updatedSchema;
791						emitter.emitAction(nestedActionEvent.event, nestedActionEvent.meta, nestedActionEvent.context);
792					}
793				}
794			}
795		}
