 32		private async validateCreateData(data: Partial<Item>): Promise<void> {
 33			const versionCreateSchema = Joi.object({
 34				key: Joi.string().required(),
 35				name: Joi.string().allow(null),
 36				collection: Joi.string().required(),
 37				item: Joi.string().required(),
 38			});
 39	
 40			const { error } = versionCreateSchema.validate(data);
 41			if (error) throw new InvalidPayloadError({ reason: error.message });
 42	
 43			// Reserves the "main" version key for the version query parameter
 44			if (data['key'] === 'main') throw new InvalidPayloadError({ reason: `"main" is a reserved version key` });
 45	
 46			if (this.accountability) {
 47				try {
 48					await validateAccess(
 49						{
 50							accountability: this.accountability,
 51							action: 'read',
 52							collection: data['collection'],
 53							primaryKeys: [data['item']],
 54						},
 55						{
 56							schema: this.schema,
 57							knex: this.knex,
 58						},
 59					);
 60				} catch {
 61					throw new ForbiddenError();
 62				}
 63			}
 64	
 65			const { CollectionsService } = await import('./collections.js');
 66	
 67			const collectionsService = new CollectionsService({
 68				knex: this.knex,
 69				schema: this.schema,
 70			});
 71	
 72			const existingCollection = await collectionsService.readOne(data['collection']);
 73	
 74			if (!existingCollection.meta?.versioning) {
 75				throw new UnprocessableContentError({
 76					reason: `Content Versioning is not enabled for collection "${data['collection']}"`,
 77				});
 78			}
 79	
 80			const sudoService = new VersionsService({
 81				knex: this.knex,
 82				schema: this.schema,
 83			});
 84	
 85			const existingVersions = (await sudoService.readByQuery({
 86				aggregate: { count: ['*'] },
 87				filter: { key: { _eq: data['key'] }, collection: { _eq: data['collection'] }, item: { _eq: data['item'] } },
 88			})) as any[];
 89	
 90			if (existingVersions[0]['count'] > 0) {
 91				throw new UnprocessableContentError({
 92					reason: `Version "${data['key']}" already exists for item "${data['item']}" in collection "${data['collection']}"`,
 93				});
 94			}
 95		}
