 97		async getMainItem(collection: string, item: PrimaryKey, query?: Query): Promise<Item> {
 98			const itemsService = new ItemsService(collection, {
 99				knex: this.knex,
100				accountability: this.accountability,
101				schema: this.schema,
102			});
103	
104			return await itemsService.readOne(item, query);
105		}
