107		async verifyHash(
108			collection: string,
109			item: PrimaryKey,
110			hash: string,
111		): Promise<{ outdated: boolean; mainHash: string }> {
112			const mainItem = await this.getMainItem(collection, item);
113	
114			const mainHash = objectHash(mainItem);
115	
116			return { outdated: hash !== mainHash, mainHash };
117		}
