119		async getVersionSave(key: string, collection: string, item: string, mapDelta = true) {
120			const version = (
121				await this.readByQuery({
122					filter: {
123						key: { _eq: key },
124						collection: { _eq: collection },
125						item: { _eq: item },
126					},
127				})
128			)[0];
129	
130			if (mapDelta && version?.delta) version.delta = this.mapDelta(version);
131	
132			return version;
