153		override async createMany(data: Partial<Item>[], opts?: MutationOptions): Promise<PrimaryKey[]> {
154			if (!Array.isArray(data)) {
155				throw new InvalidPayloadError({ reason: 'Input should be an array of items' });
156			}
157	
158			const keyCombos = new Set();
159	
160			for (const item of data) {
161				const keyCombo = `${item['key']}-${item['collection']}-${item['item']}`;
162	
163				if (keyCombos.has(keyCombo)) {
164					throw new UnprocessableContentError({
165						reason: `Cannot create multiple versions on "${item['item']}" in collection "${item['collection']}" with the same key "${item['key']}"`,
166					});
167				}
168	
169				keyCombos.add(keyCombo);
170			}
171	
172			return super.createMany(data, opts);
173		}
