175		override async updateMany(keys: PrimaryKey[], data: Partial<Item>, opts?: MutationOptions): Promise<PrimaryKey[]> {
176			// Only allow updates on "key" and "name" fields
177			const versionUpdateSchema = Joi.object({
178				key: Joi.string(),
179				name: Joi.string().allow(null),
180			});
181	
182			const { error } = versionUpdateSchema.validate(data);
183			if (error) throw new InvalidPayloadError({ reason: error.message });
184	
185			if ('key' in data) {
186				// Reserves the "main" version key for the version query parameter
187				if (data['key'] === 'main') throw new InvalidPayloadError({ reason: `"main" is a reserved version key` });
188	
189				const keyCombos = new Set();
190	
191				for (const pk of keys) {
192					const { collection, item } = await this.readOne(pk, { fields: ['collection', 'item'] });
193	
194					const keyCombo = `${data['key']}-${collection}-${item}`;
195	
196					if (keyCombos.has(keyCombo)) {
197						throw new UnprocessableContentError({
198							reason: `Cannot update multiple versions on "${item}" in collection "${collection}" to the same key "${data['key']}"`,
199						});
200					}
201	
202					keyCombos.add(keyCombo);
203	
204					const existingVersions = await super.readByQuery({
205						aggregate: { count: ['*'] },
206						filter: { id: { _neq: pk }, key: { _eq: data['key'] }, collection: { _eq: collection }, item: { _eq: item } },
207					});
208	
209					if ((existingVersions as any)[0]['count'] > 0) {
210						throw new UnprocessableContentError({
211							reason: `Version "${data['key']}" already exists for item "${item}" in collection "${collection}"`,
212						});
213					}
214				}
215			}
216	
217			return super.updateMany(keys, data, opts);
218		}
