220		async save(key: PrimaryKey, delta: Partial<Item>): Promise<Partial<Item>> {
221			const version = await super.readOne(key);
222	
223			const payloadService = new PayloadService(this.collection, {
224				accountability: this.accountability,
225				knex: this.knex,
226				schema: this.schema,
227			});
228	
229			const activityService = new ActivityService({
230				knex: this.knex,
231				schema: this.schema,
232			});
233	
234			const revisionsService = new RevisionsService({
235				knex: this.knex,
236				schema: this.schema,
237			});
238	
239			const { item, collection, delta: existingDelta } = version;
240	
241			const activity = await activityService.createOne({
242				action: Action.VERSION_SAVE,
243				user: this.accountability?.user ?? null,
244				collection,
245				ip: this.accountability?.ip ?? null,
246				user_agent: this.accountability?.userAgent ?? null,
247				origin: this.accountability?.origin ?? null,
248				item,
249			});
250	
251			const helpers = getHelpers(this.knex);
252	
253			let revisionDelta = await payloadService.prepareDelta(delta);
254	
255			await revisionsService.createOne({
256				activity,
257				version: key,
258				collection,
259				item,
260				data: revisionDelta,
261				delta: revisionDelta,
262			});
263	
264			revisionDelta = revisionDelta ? revisionDelta : null;
265	
266			const date = new Date(helpers.date.writeTimestamp(new Date().toISOString()));
267	
268			deepMapObjects(revisionDelta, (object, path) => {
269				const existing = get(existingDelta, path);
270	
271				if (existing && isEqual(existing, object)) return;
272	
273				object['_user'] = this.accountability?.user;
274				object['_date'] = date;
275			});
276	
277			const finalVersionDelta = assign({}, existingDelta, revisionDelta);
278	
279			const sudoService = new ItemsService(this.collection, {
280				knex: this.knex,
281				schema: this.schema,
282				accountability: {
283					...this.accountability!,
284					admin: true,
285				},
286			});
287	
288			await sudoService.updateOne(key, { delta: finalVersionDelta });
289	
290			const { cache } = getCache();
291	
292			if (shouldClearCache(cache, undefined, collection)) {
293				cache.clear();
294			}
295	
296			return finalVersionDelta;
297		}
