299		async promote(version: PrimaryKey, mainHash: string, fields?: string[]) {
300			const { collection, item, delta } = (await super.readOne(version)) as ContentVersion;
301	
302			// will throw an error if the accountability does not have permission to update the item
303			if (this.accountability) {
304				await validateAccess(
305					{
306						accountability: this.accountability,
307						action: 'update',
308						collection,
309						primaryKeys: [item],
310					},
311					{
312						schema: this.schema,
313						knex: this.knex,
314					},
315				);
316			}
317	
318			if (!delta) {
319				throw new UnprocessableContentError({
320					reason: `No changes to promote`,
321				});
322			}
323	
324			const { outdated } = await this.verifyHash(collection, item, mainHash);
325	
326			if (outdated) {
327				throw new UnprocessableContentError({
328					reason: `Main item has changed since this version was last updated`,
329				});
330			}
331	
332			const { rawDelta, defaultOverwrites } = splitRecursive(delta);
333	
334			const payloadToUpdate = fields ? pick(rawDelta, fields) : rawDelta;
335	
336			const itemsService = new ItemsService(collection, {
337				accountability: this.accountability,
338				knex: this.knex,
339				schema: this.schema,
340			});
341	
342			const payloadAfterHooks = await emitter.emitFilter(
343				['items.promote', `${collection}.items.promote`],
344				payloadToUpdate,
345				{
346					collection,
347					item,
348					version,
349				},
350				{
351					database: this.knex,
352					schema: this.schema,
353					accountability: this.accountability,
354				},
355			);
356	
357			const updatedItemKey = await itemsService.updateOne(item, payloadAfterHooks, {
358				overwriteDefaults: defaultOverwrites as any,
359			});
360	
361			emitter.emitAction(
362				['items.promote', `${collection}.items.promote`],
363				{
364					payload: payloadAfterHooks,
365					collection,
366					item: updatedItemKey,
367					version,
368				},
369				{
370					database: this.knex,
371					schema: this.schema,
372					accountability: this.accountability,
373				},
374			);
375	
376			return updatedItemKey;
377		}
