379		private mapDelta(version: ContentVersion) {
380			const delta = version.delta ?? {};
381			delta[this.schema.collections[version.collection]!.primary] = version.item;
382	
383			return deepMapWithSchema(
384				delta,
385				([key, value], context) => {
386					if (key === '_user' || key === '_date') return;
387	
388					if (context.collection.primary in context.object) {
389						if (context.field.special.includes('user-updated')) {
390							return [key, context.object['_user']];
391						}
392	
393						if (context.field.special.includes('date-updated')) {
394							return [key, context.object['_date']];
